export type MusicTrack = {
  id: string
  title: string
  artist: string
  cover: string
  audioUrl: string
  source: 'local' | 'netease' | 'qq'
  externalUrl?: string
}

export type PhotoItem = {
  id: string
  title: string
  category: string
  src: string
  thumb: string
  date: string
  location: string
}

export type GameItem = {
  id: string
  name: string
  cover: string
  screenshots: string[]
  lastPlayedOrUpdated: string
  tags: string[]
}

export type ProjectItem = {
  id: string
  name: string
  type: string
  techStack: string[]
  summary: string
  path: string
  featured: boolean
}

export type SkillItem = {
  label: string
  value: number
  detail: string
}

export type SiteContent = {
  photos: PhotoItem[]
  games: GameItem[]
  projects: ProjectItem[]
  localTracks: MusicTrack[]
  skills: SkillItem[]
}

const photo = (id: string, title: string, category: string, date: string, location: string): PhotoItem => ({
  id,
  title,
  category,
  src: `/assets/optimized/photos/${id}.webp`,
  thumb: `/assets/optimized/photos/${id}-thumb.webp`,
  date,
  location,
})

const photoAsset = (
  id: string,
  title: string,
  category: string,
  date: string,
  location: string,
  src: string,
  thumb: string,
): PhotoItem => ({
  id,
  title,
  category,
  src,
  thumb,
  date,
  location,
})

